// src/data/users.repo.ts
import { db } from "./client.ts";

// DB1 (N+1): one query PER id, issued sequentially inside the loop — for a 500-id
// batch this fires 500 round-trips instead of one. Classic N+1 in a hot path.
export async function loadUsers(ids: string[]) {
  const users = [];
  for (const id of ids) {
    users.push(await db.user.findUnique({ where: { id } }));
  }
  return users;
}

// DB12 (SQL injection): the caller's email is concatenated straight into raw SQL and
// run via $queryRawUnsafe — an attacker sending ' OR '1'='1 rewrites the query.
export async function searchByEmail(email: string) {
  return db.$queryRawUnsafe(
    "SELECT id, email FROM users WHERE email = '" + email + "'",
  );
}

// DB1 (unbounded): findMany with no take/limit — loads the entire orders table into
// memory, an OOM risk as the table grows.
export async function allOrders() {
  return db.order.findMany();
}

// src/data/client.ts  (thin ORM-style client stub)
export const db = {
  user: {
    async findUnique(_args: { where: { id: string } }): Promise<unknown> { return null; },
    async findMany(_args?: unknown): Promise<unknown[]> { return []; },
  },
  order: {
    async findMany(_args?: unknown): Promise<unknown[]> { return []; },
  },
  // Tagged-template raw query (parameterized/safe).
  async $queryRaw(_strings: TemplateStringsArray, ..._values: unknown[]): Promise<unknown[]> { return []; },
  // Unsafe raw query (caller-built string — injection sink).
  async $queryRawUnsafe(_sql: string): Promise<unknown[]> { return []; },
};

// src/data/users.repo.ts
import { db } from "./client.ts";

// SAFE: a single batched query with an `in` filter fetches every id at once — no N+1.
export async function loadUsers(ids: string[]) {
  return db.user.findMany({ where: { id: { in: ids } } });
}

// SAFE: the email is interpolated through a TAGGED TEMPLATE ($queryRaw), so the ORM binds
// it as a parameter — no string concatenation, no injection.
export async function searchByEmail(email: string) {
  return db.$queryRaw`SELECT id, email FROM users WHERE email = ${email}`;
}

// SAFE: findMany is bounded by an explicit take (clamped page size) with a stable order —
// no unbounded full-table scan.
export async function recentOrders(limit = 50) {
  return db.order.findMany({ take: Math.min(limit, 100), orderBy: { id: "desc" } });
}

// src/data/client.ts  (thin ORM-style client stub)
export const db = {
  user: {
    async findUnique(_args: { where: { id: string } }): Promise<unknown> { return null; },
    async findMany(_args?: unknown): Promise<unknown[]> { return []; },
  },
  order: {
    async findMany(_args?: unknown): Promise<unknown[]> { return []; },
  },
  // Tagged-template raw query (parameterized/safe).
  async $queryRaw(_strings: TemplateStringsArray, ..._values: unknown[]): Promise<unknown[]> { return []; },
  // Unsafe raw query (caller-built string — injection sink).
  async $queryRawUnsafe(_sql: string): Promise<unknown[]> { return []; },
};
